public int sumOfSubarrayRanges(int[] nums) {
    int n = nums.length;
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = i; j < n; ++j) {
            ans += maxElement(nums, i, j) - minElement(nums, i, j);
        }
    }
    return ans;
}

private int maxElement(int[] nums, int start, int end) {
    int max = nums[start];
    for (int i = start + 1; i <= end; ++i) {
        max = Math.max(max, nums[i]);
    }
    return max;
}

private int minElement(int[] nums, int start, int end) {
    int min = nums[start];
    for (int i = start + 1; i <= end; ++i) {
        min = Math.min(min, nums[i]);
    }
    return min;
}
```

